 10	  AffinityCondition,
 11	  AffinityLabel,
 12	  AffinityRowData,
 13	  AffinityType,
 14	} from '../../../utils/types';
 15	
 16	import AffinityConditionSelect from './components/AffinityConditionSelect';
 17	import AffinityTypeSelect from './components/AffinityTypeSelect';
 18	import ExpressionEditList from './components/ExpressionEditList';
 19	import FieldsEditList from './components/FieldsEditList';
 20	import NodeExpressionDescriptionText from './components/NodeExpressionDescriptionText';
 21	import NodeFieldsDescriptionText from './components/NodeFieldsDescriptionText';
 22	import PrefferedAffinityWeightInput from './components/PrefferedAffinityWeightInput';
 23	import TopologyKeyInput from './components/TopologyKeyInput';
 24	import WorkloadExpressionDescriptionText from './components/WorkloadExpressionDescriptionText';
 25	
 26	export type useIDEntitiesValue = {
 27	  entities: AffinityLabel[];
 28	  initialEntitiesChanged: boolean;
 29	  onEntityAdd: (newEntity: AffinityLabel) => void;
 30	  onEntityChange: (updatedEntity: AffinityLabel) => void;
 31	  onEntityDelete: (idToDelete: number) => void;
 32	  setEntities: React.Dispatch<React.SetStateAction<AffinityLabel[]>>;
 33	};
 34	
 35	type AffinityFormProps = {
 36	  expressions: useIDEntitiesValue;
 37	  fields: useIDEntitiesValue;
 38	  focusedAffinity: AffinityRowData;
 39	  isSubmitDisabled: boolean;
 40	  nodesLoaded: boolean;
 41	  qualifiedNodes: IoK8sApiCoreV1Node[];
 42	  setFocusedAffinity: React.Dispatch<React.SetStateAction<AffinityRowData>>;
 43	  setSubmitDisabled: React.Dispatch<React.SetStateAction<boolean>>;
 44	};
 45	
 46	const AffinityForm: React.FC<AffinityFormProps> = ({
 47	  expressions,
 48	  fields,
 49	  focusedAffinity,
 50	  isSubmitDisabled,
 51	  nodesLoaded,
 52	  qualifiedNodes,
 53	  setFocusedAffinity,
 54	  setSubmitDisabled,
 55	}) => {
 56	  const { t } = useKubevirtTranslation();
 57	
 58	  const isNodeAffinity = focusedAffinity?.type === AffinityType.node;
 59	
 60	  React.useEffect(() => {
 61	    setSubmitDisabled(
 62	      (expressions?.entities?.length === 0 && fields?.entities?.length === 0) ||
 63	        isTermsInvalid(expressions?.entities) ||
 64	        isTermsInvalid(fields?.entities),
 65	    );
 66	  }, [expressions, fields, setSubmitDisabled]);
 67	
 68	  return (
 69	    <Form>
 70	      <Text className="text-muted" component={TextVariants.p}>
 71	        {t(
 72	          'Define an affinity rule. This rule will be added to the list of affinity rules applied to this workload.',
 73	        )}
 74	      </Text>
 75	      <AffinityTypeSelect
 76	        focusedAffinity={focusedAffinity}
 77	        setFocusedAffinity={setFocusedAffinity}
 78	      />
 79	      <AffinityConditionSelect
 80	        focusedAffinity={focusedAffinity}
 81	        setFocusedAffinity={setFocusedAffinity}
 82	      />
 83	      {focusedAffinity?.condition === AffinityCondition.preferred && (
 84	        <PrefferedAffinityWeightInput
 85	          focusedAffinity={focusedAffinity}
 86	          setFocusedAffinity={setFocusedAffinity}
 87	          setSubmitDisabled={setSubmitDisabled}
 88	        />
 89	      )}
 90	      {!isNodeAffinity && (
 91	        <TopologyKeyInput
 92	          focusedAffinity={focusedAffinity}
 93	          setFocusedAffinity={setFocusedAffinity}
 94	          setSubmitDisabled={setSubmitDisabled}
 95	        />
 96	      )}
 97	      <Divider />
 98	      <ExpressionEditList
 99	        errorHelperText={t('Missing fields in {{kind}} labels', {
100	          kind: isNodeAffinity ? 'Node' : 'Workload',
101	        })}
102	        helperText={
103	          isNodeAffinity ? <NodeExpressionDescriptionText /> : <WorkloadExpressionDescriptionText />
104	        }
105	        expressions={expressions}
106	        label={isNodeAffinity ? t('Node labels') : t('Workload labels')}
107	      />
108	      {isNodeAffinity && (
109	        <>
110	          <Divider />
111	          <FieldsEditList
112	            errorHelperText={t('Missing fields in Node fields')}
113	            fields={fields}
114	            helperText={<NodeFieldsDescriptionText />}
115	            label={t('Node fields')}
116	          />
117	        </>
118	      )}
119	      {isNodeAffinity && nodesLoaded && !isSubmitDisabled && (
120	        <NodeCheckerAlert nodesLoaded={nodesLoaded} qualifiedNodes={qualifiedNodes} />
121	      )}
122	    </Form>
123	  );
124	};
125	export default AffinityForm;

